            {"en": "I have been to Paris.", "de": "Ich bin in Paris gewesen.", "fr": "Je suis alle a Paris.", "it": "Sono stato a Parigi.", "es": "He estado en Paris.", "tr": "Paris'e gittim / Paris'te bulundum."},
