        # 10. Connectors (5 examples)
        {"title": "Connectors", "rule_tr": "although (ragmen), however (ancak), furthermore (dahasi), moreover (ayrica)", "examples": [
            {"en": "Although it was raining, we went for a walk.", "de": "Obwohl es regnete, gingen wir spazieren.", "fr": "Bien qu'il pleuve, nous sommes alles nous promener.", "it": "Sebbene piovesse, siamo andati a fare una passeggiata.", "es": "Aunque llovia, salimos a caminar.", "tr": "Yagmur yagmasina ragmen yuruyuse ciktik."},
            {"en": "The movie was long; however, it was very entertaining.", "de": "Der Film war lang; allerdings war er sehr unterhaltsam.", "fr": "Le film etait long; cependant, il etait tres divertissant.", "it": "Il film era lungo; tuttavia, era molto divertente.", "es": "La pelicula era larga; sin embargo, era muy entretenida.", "tr": "Film uzundu; ancak cok eglenceciydi."},
            {"en": "She speaks French. Furthermore, she is learning German.", "de": "Sie spricht Franzosisch. Daruber hinaus lernt sie Deutsch.", "fr": "Elle parle francais. De plus, elle apprend l'allemand.", "it": "Parla francese. Inoltre, sta imparando il tedesco.", "es": "Habla frances. Ademas, esta aprendiendo aleman.", "tr": "Fransizca konusuyor. Dahasi, Almanca ogreniyor."},
            {"en": "The food was delicious. Moreover, the service was excellent.", "de": "Das Essen war kostlich. Ausserdem war der Service ausgezeichnet.", "fr": "La nourriture etait delicieuse. De plus, le service etait excellent.", "it": "Il cibo era delizioso. Inoltre, il servizio era eccellente.", "es": "La comida estaba deliciosa. Ademas, el servicio era excelente.", "tr": "Yemek lezzetliydi. Ayrica servis mukemmeldi."},
            {"en": "He is young; nevertheless, he has a lot of experience.", "de": "Er ist jung; nichtsdestotrotz hat er viel Erfahrung.", "fr": "Il est jeune; neanmoins, il a beaucoup d'experience.", "it": "E giovane; tuttavia, ha molta esperienza.", "es": "Es joven; sin embargo, tiene mucha experiencia.", "tr": "Genc; yine de cok deneyimli."},
        ], "exercises": [
            {"prompt": "___ it was cold, she went swimming.", "answer": "Although", "hint": "-e ragmen"},
            {"prompt": "The test was hard; ___, most students passed.", "answer": "however", "hint": "ancak / buna ragmen"},
            {"prompt": "He is smart. ___, he works very hard.", "answer": "Furthermore", "hint": "Dahasi / Ayrica"},
            {"prompt": "The hotel was clean. ___, it was affordable.", "answer": "Moreover", "hint": "Ayrica / Ustune ustluk"},
            {"prompt": "She was tired; ___, she finished the project.", "answer": "nevertheless", "hint": "yine de / buna ragmen"},
        ]},
